                            } else if (sel_click_count == 2) {
                                const wb = TextEngine.wordBoundsAt(txt, byte_idx);
                                sel_node = tnode;
                                sel_end_node = tnode;
                                sel_start = wb.start;
                                sel_end = wb.end;
                                sel_anchor = wb.start;
                                sel_dragging = false;
                            } else {
                                sel_node = tnode;
                                sel_end_node = tnode;
                                sel_anchor = byte_idx;
                                sel_start = byte_idx;
                                sel_end = byte_idx;
                                sel_dragging = true;
                            }
                        }
                    } else {
                        sel_node = null;
                        sel_end_node = null;
                        sel_start = 0;
                        sel_end = 0;
                    }
                    }
                },
                c.SDL_MOUSEBUTTONUP => {
                    sel_dragging = false;
                },
                c.SDL_MOUSEWHEEL => {
                    var mx_i: c_int = undefined; var my_i: c_int = undefined;
                    _ = c.SDL_GetMouseState(&mx_i, &my_i);
                    const mx: f32 = @floatFromInt(mx_i); const my: f32 = @floatFromInt(my_i);
                    if (events.findScrollContainer(&root, mx, my)) |scroll_node| {
                        scroll_node.scroll_y -= @as(f32, @floatFromInt(event.wheel.y)) * 30.0;
                        const max_scroll = @max(0.0, scroll_node.content_height - scroll_node.computed.h);
                        scroll_node.scroll_y = @max(0.0, @min(scroll_node.scroll_y, max_scroll));
                    }
                },
                else => {},
            }
        }

        if (watchdog.check()) {
            win_mgr.deinitAll();
            c.SDL_DestroyRenderer(renderer);
            c.SDL_DestroyWindow(window);
            bsod.show(watchdog.getLastReason(), watchdog.getLastDetail());
            return;
        }
        mpv_mod.poll();
        layout.layout(&root, 0, 0, win_w, win_h);
        painter.clear(Color.rgb(24, 24, 32));
        sel_paint_state = 0;
        painter.paintTree(&root, 0, 0);
        painter.present();
        win_mgr.layoutAll();
        win_mgr.paintAndPresent(brighten);
    }
}
